// 三载体一致:纯 JS、无 DOM/uplink/shadow 足迹
import * as D from 'https://cdn.jsdelivr.net/npm/dinero.js@2/+esm';
const code = data.currency ?? 'USD', currency = D[code];
if (!currency || typeof currency.exponent !== 'number') throw new Error('Unsupported ISO currency');
const money = D.dinero({ amount: data.amount, currency, ...(data.scale === undefined ? {} : { scale: data.scale }) });
const allocations = data.ratios === undefined ? undefined : D.allocate(money, data.ratios);
const result = { money, decimal: D.toDecimal(money), allocations };
